package org.example;
import java.util.ArrayList;

public class App {
    public static void main(String[] args) {
        ArrayList<Thread> threads = new ArrayList<>();

        for (int i = 0; i < 3; i++) {
            Thread thread = new Thread(new ManejarAuto(i));
            threads.add(thread);
            thread.start();
        }
        
        for (Thread thread : threads) {
            try {
                thread.join();
            } catch (InterruptedException e) {
                e.printStackTrace();
            }
        }

        System.out.println("¡Todos llegaron a la meta!");
    }

    static class ManejarAuto implements Runnable {
        private Auto auto;
        private int id;

        public ManejarAuto(int id) {
            this.auto = new Auto();
            this.id = id;
        }

        @Override
        public void run() {
            while (!auto.llegoALaMeta()) {
                auto.avanzar();
                try {
                    Thread.sleep(1000); // Simula el tiempo que tarda en avanzar
                } catch (InterruptedException e) {
                    e.printStackTrace();
                }
            }
            System.out.println("El auto "+ id + " llegó");
        }
    }
}
